function LFightIdleBeHitAction:ResetDefaultAction()
	if self._obj:SetStatus(LFightIdleConst.STATUS_IDLE) then
		self._obj:PlayIdleAni()
	end
	local ai = self._ai
	ai:ChangeAction(ai:GetDefaultAction())
end

-----------------------------------------------------------------
function LFightIdleBeHitAction:StartAction()
	local hitAni,hitTime = self._obj:GetHitActionData()
	self._hitAni = hitAni
	self._hitTime = hitTime

	self._hitEndTime = self._hitTime + self:GetTime()
	self._obj:StopActor()
	self._obj:SetStatus(LFightIdleConst.STATUS_BEHIT)
	self._obj:PlayAni(self._hitAni)
end

